from pathlib import Path as _Path


def load_ch_hotspots(ch_maf_path: _Path | str) -> set[tuple]:
    """Load a CH hotspot MAF file and return a set of variant keys.

    The MAF file must have columns: Hugo_Symbol, Chromosome,
    Start_Position, Reference_Allele, Tumor_Seq_Allele2.

    Each row is converted to a (chrom, pos, ref, alt) tuple for fast
    lookup during SNV summary computation.
    """
    try:
        ch_df = pd.read_csv(ch_maf_path, sep="\t", comment="#")
        required = {
            "Chromosome",
            "Start_Position",
            "Reference_Allele",
            "Tumor_Seq_Allele2",
        }
        missing = required - set(ch_df.columns)
        if missing:
            raise ValueError(f"CH hotspot MAF missing required columns: {missing}")

        ch_set = set()
        for _, row in ch_df.iterrows():
            ch_set.add(
                (
                    str(row["Chromosome"]),
                    int(row["Start_Position"]),
                    str(row["Reference_Allele"]),
                    str(row["Tumor_Seq_Allele2"]),
                )
            )

        log.info(
            "ch_hotspots_loaded",
            path=str(ch_maf_path),
            n_hotspots=len(ch_set),
        )
        return ch_set
    except Exception as e:
        log.error("ch_hotspot_load_failed", path=str(ch_maf_path), error=str(e))
        raise


# %% ../nbs/01_labels.ipynb #6333e679
def _build_patient_impact_variants(
    maf: pd.DataFrame,
    clinical: pd.DataFrame,
) -> dict[str, set[tuple]]:
    """Build a lookup: patient_id → set of somatic variant keys from IMPACT samples."""
    try:
        impact_samples = clinical[clinical["GENE_PANEL"].isin(IMPACT_PANELS)][
            ["SAMPLE_ID", "PATIENT_ID"]
        ]

        impact_maf = maf[
            (maf["Tumor_Sample_Barcode"].isin(set(impact_samples["SAMPLE_ID"])))
            & (maf["Mutation_Status"] == "SOMATIC")
        ].copy()

        if impact_maf.empty:
            log.warning("no_impact_somatic_variants", n_samples=len(impact_samples))
            return {}

        impact_maf = impact_maf.merge(
            impact_samples,
            left_on="Tumor_Sample_Barcode",
            right_on="SAMPLE_ID",
            how="inner",
        )

        impact_maf["variant_key"] = make_variant_key(impact_maf)

        result = impact_maf.groupby("PATIENT_ID")["variant_key"].apply(set).to_dict()
        log.info(
            "built_impact_lookup",
            n_patients=len(result),
            n_variant_keys=sum(len(v) for v in result.values()),
        )
        return result
    except Exception as e:
        log.error("impact_lookup_build_failed", error=str(e))
        raise


def compute_impact_match(
    eligible_ids: set[str],
    maf: pd.DataFrame,
    clinical: pd.DataFrame,
) -> pd.DataFrame:
    """For each eligible ACCESS sample, check if any somatic variant (any VAF)
    also appears in the same patient's IMPACT tissue sample.
    """
    try:
        access_patients = clinical[clinical["SAMPLE_ID"].isin(eligible_ids)][
            ["SAMPLE_ID", "PATIENT_ID"]
        ].drop_duplicates()

        patient_impact_vars = _build_patient_impact_variants(maf, clinical)
        patients_with_impact = set(patient_impact_vars.keys())

        access_maf = maf[
            (maf["Tumor_Sample_Barcode"].isin(eligible_ids))
            & (maf["Mutation_Status"] == "SOMATIC")
        ].copy()

        if len(access_maf) == 0:
            return pd.DataFrame(
                {
                    "SAMPLE_ID": list(eligible_ids),
                    "has_impact_match": False,
                    "n_impact_confirmed": 0,
                    "has_paired_impact": [
                        (
                            access_patients.loc[
                                access_patients["SAMPLE_ID"] == s, "PATIENT_ID"
                            ].iloc[0]
                            in patients_with_impact
                            if s in access_patients["SAMPLE_ID"].values
                            else False
                        )
                        for s in eligible_ids
                    ],
                }
            )

        access_maf = access_maf.merge(
            access_patients,
            left_on="Tumor_Sample_Barcode",
            right_on="SAMPLE_ID",
            how="inner",
        )

        access_maf["variant_key"] = make_variant_key(access_maf)

        access_maf["in_impact"] = access_maf.apply(
            lambda row: (
                row["PATIENT_ID"] in patient_impact_vars
                and row["variant_key"] in patient_impact_vars[row["PATIENT_ID"]]
            ),
            axis=1,
        )

        per_sample = (
            access_maf.groupby("Tumor_Sample_Barcode")
            .agg(
                has_impact_match=("in_impact", "any"),
                n_impact_confirmed=("in_impact", "sum"),
                _patient_id=("PATIENT_ID", "first"),
            )
            .reset_index()
            .rename(columns={"Tumor_Sample_Barcode": "SAMPLE_ID"})
        )
        per_sample["has_paired_impact"] = per_sample["_patient_id"].isin(
            patients_with_impact
        )
        per_sample = per_sample.drop(columns=["_patient_id"])

        missing = eligible_ids - set(per_sample["SAMPLE_ID"])
        if missing:
            missing_patients = access_patients[
                access_patients["SAMPLE_ID"].isin(missing)
            ]
            missing_df = pd.DataFrame(
                {
                    "SAMPLE_ID": list(missing),
                    "has_impact_match": False,
                    "n_impact_confirmed": 0,
                }
            )
            missing_df = missing_df.merge(missing_patients, on="SAMPLE_ID", how="left")
            missing_df["has_paired_impact"] = missing_df["PATIENT_ID"].isin(
                patients_with_impact
            )
            missing_df = missing_df.drop(columns=["PATIENT_ID"])
            per_sample = pd.concat([per_sample, missing_df], ignore_index=True)

        log.info(
            "impact_match_computed",
            matched=int(per_sample["has_impact_match"].sum()),
            paired_impact=int(per_sample["has_paired_impact"].sum()),
        )
        return per_sample
    except Exception as e:
        log.error("compute_impact_match_failed", error=str(e))
        raise


# %% ../nbs/01_labels.ipynb #41a901ed
def compute_snv_summary(
    eligible_ids: set[str],
    maf: pd.DataFrame,
    min_vaf: float = 0.01,
    min_variants: int = 1,
    ch_variants: set[tuple] | None = None,
) -> pd.DataFrame:
    """Summarize somatic SNV status per eligible sample.

    Returns one row per eligible sample with columns:
        has_snv, n_somatic_snvs, n_total_somatic_snvs,
        max_vaf, mean_vaf, std_vaf, n_ch_variants, n_non_ch_variants.

    mean_vaf and std_vaf are computed only from VAF-passing variants
    (those above ``min_vaf``), providing continuous regression targets
    for the Stage 2 Quantifier.

    If ``ch_variants`` is provided, variants matching CH hotspots are
    tagged and counted separately. n_non_ch_variants counts only
    VAF-passing, non-CH variants — the key input for CH-only demotion.
    """
    try:
        somatic = maf[
            (maf["Tumor_Sample_Barcode"].isin(eligible_ids))
            & (maf["Mutation_Status"] == "SOMATIC")
        ].copy()

        if len(somatic) == 0:
            return pd.DataFrame(
                {
                    "SAMPLE_ID": list(eligible_ids),
                    "has_snv": False,
                    "n_somatic_snvs": 0,
                    "n_total_somatic_snvs": 0,
                    "max_vaf": 0.0,
                    "mean_vaf": 0.0,
                    "std_vaf": 0.0,
                    "n_ch_variants": 0,
                    "n_non_ch_variants": 0,
                }
            )

        total_depth = somatic["t_ref_count"] + somatic["t_alt_count"]
        somatic["VAF"] = np.where(
            total_depth > 0,
            somatic["t_alt_count"] / total_depth,
            0.0,
        )

        # Tag CH hotspot variants if a reference set was provided
        if ch_variants is not None:
            somatic["is_ch"] = somatic.apply(
                lambda r: (
                    str(r.get("Chromosome", "")),
                    (
                        int(r["Start_Position"])
                        if pd.notna(r.get("Start_Position"))
                        else 0
                    ),
                    str(r.get("Reference_Allele", "")),
                    str(r.get("Tumor_Seq_Allele2", "")),
                )
                in ch_variants,
                axis=1,
            )
            log.info(
                "ch_variants_tagged",
                n_ch_hits=int(somatic["is_ch"].sum()),
                n_total_somatic=len(somatic),
            )
        else:
            somatic["is_ch"] = False

        def _agg(group: pd.DataFrame) -> pd.Series:
            passing = group[group["VAF"] >= min_vaf]
            n_ch = int(passing["is_ch"].sum()) if "is_ch" in passing.columns else 0
            n_non_ch = len(passing) - n_ch
            return pd.Series(
                {
                    "has_snv": len(passing) >= min_variants,
                    "n_somatic_snvs": len(passing),
                    "n_total_somatic_snvs": len(group),
                    "max_vaf": group["VAF"].max(),
                    "mean_vaf": (
                        float(passing["VAF"].mean()) if len(passing) > 0 else 0.0
                    ),
                    "std_vaf": float(passing["VAF"].std()) if len(passing) > 1 else 0.0,
                    "n_ch_variants": n_ch,
                    "n_non_ch_variants": n_non_ch,
                }
            )

        per_sample = (
            somatic.groupby("Tumor_Sample_Barcode")
            .apply(_agg, include_groups=False)
            .reset_index()
            .rename(columns={"Tumor_Sample_Barcode": "SAMPLE_ID"})
        )

        missing = eligible_ids - set(per_sample["SAMPLE_ID"])
        if missing:
            missing_df = pd.DataFrame(
                {
                    "SAMPLE_ID": list(missing),
                    "has_snv": False,
                    "n_somatic_snvs": 0,
                    "n_total_somatic_snvs": 0,
                    "max_vaf": 0.0,
                    "mean_vaf": 0.0,
                    "std_vaf": 0.0,
                    "n_ch_variants": 0,
                    "n_non_ch_variants": 0,
                }
            )
            per_sample = pd.concat([per_sample, missing_df], ignore_index=True)

        log.info(
            "snv_summary_computed",
            min_vaf=min_vaf,
            min_variants=min_variants,
            positive_samples=int(per_sample["has_snv"].sum()),
            cohort_mean_vaf=round(float(per_sample["mean_vaf"].mean()), 4),
            cohort_max_vaf=round(float(per_sample["max_vaf"].max()), 4),
        )
        return per_sample
    except Exception as e:
        log.error("compute_snv_summary_failed", error=str(e))
        raise


# %% ../nbs/01_labels.ipynb #c9709211
def compute_sv_summary(
    eligible_ids: set[str],
    sv_df: pd.DataFrame,
) -> pd.DataFrame:
    """Summarize somatic SV status per eligible sample (binary presence/absence)."""
    try:
        somatic_sv = sv_df[
            (sv_df["Sample_ID"].isin(eligible_ids)) & (sv_df["SV_Status"] == "SOMATIC")
        ]

        if len(somatic_sv) == 0:
            return pd.DataFrame(
                {
                    "SAMPLE_ID": list(eligible_ids),
                    "has_sv": False,
                    "n_somatic_svs": 0,
                }
            )

        per_sample = (
            somatic_sv.groupby("Sample_ID")
            .agg(
                has_sv=("SV_Status", lambda x: True),
                n_somatic_svs=("SV_Status", "count"),
            )
            .reset_index()
            .rename(columns={"Sample_ID": "SAMPLE_ID"})
        )

        missing = eligible_ids - set(per_sample["SAMPLE_ID"])
        if missing:
            missing_df = pd.DataFrame(
                {
                    "SAMPLE_ID": list(missing),
                    "has_sv": False,
                    "n_somatic_svs": 0,
                }
            )
            per_sample = pd.concat([per_sample, missing_df], ignore_index=True)

        log.info(
            "sv_summary_computed", somatic_sv_samples=int(per_sample["has_sv"].sum())
        )
        return per_sample
    except Exception as e:
        log.error("compute_sv_summary_failed", error=str(e))
        raise


# %% ../nbs/01_labels.ipynb #e5ce6bcf
def compute_cna_summary(
    eligible_ids: set[str],
    cna_df: pd.DataFrame,
) -> pd.DataFrame:
    """Summarize CNA status per eligible sample."""
    try:
        present = [s for s in eligible_ids if s in cna_df.columns]
        absent = eligible_ids - set(present)

        rows = []
        for sample_id in present:
            col = cna_df[sample_id]
            n_events = (col.fillna(0) != 0).sum()
            rows.append(
                {
                    "SAMPLE_ID": sample_id,
                    "has_cna": n_events > 0,
                    "n_cna_events": int(n_events),
                }
            )

        for sample_id in absent:
            rows.append(
                {
                    "SAMPLE_ID": sample_id,
                    "has_cna": False,
                    "n_cna_events": 0,
                }
            )

        result = pd.DataFrame(rows)
        log.info(
            "cna_summary_computed",
            positive_samples=int(result["has_cna"].sum()),
            present_in_matrix=len(present),
            absent_from_matrix=len(absent),
        )
        return result
    except Exception as e:
        log.error("compute_cna_summary_failed", error=str(e))
        raise


